package app.org.apache.roller.weblogger.ui.struts2.core;

public class Profile extends UIAction { private static Log log = LogFactory . getLog ( Profile . class ) ; private ProfileBean bean = new ProfileBean ( ) ; private AuthMethod authMethod = WebloggerConfig . getAuthMethod ( ) ; public Profile ( ) { this . pageTitle = "yourProfile.title" ; } public boolean isWeblogRequired ( ) { return false ; } @ SkipValidation public String execute ( ) { User ud = getAuthenticatedUser ( ) ; getBean ( ) . copyFrom ( ud ) ; return INPUT ; } public String save ( ) { myValidate ( ) ; if ( ! hasActionErrors ( ) ) { User existingUser = getAuthenticatedUser ( ) ; getBean ( ) . copyTo ( existingUser ) ; if ( StringUtils . isNotEmpty ( getBean ( ) . getOpenIdUrl ( ) ) ) { try { String openidurl = getBean ( ) . getOpenIdUrl ( ) ; if ( openidurl != null && openidurl . endsWith ( "/" ) ) { openidurl = openidurl . substring ( 0 , openidurl . length ( ) - 1 ) ; } existingUser . setOpenIdUrl ( openidurl ) ; } catch ( Exception ex ) { log . error ( "Unexpected error saving user OpenID URL" , ex ) ; addError ( "generic.error.check.logs" ) ; return INPUT ; } } if ( authMethod == AuthMethod . DB_OPENID ) { if ( StringUtils . isEmpty ( existingUser . getPassword ( ) ) && StringUtils . isEmpty ( bean . getPasswordText ( ) ) && StringUtils . isEmpty ( bean . getOpenIdUrl ( ) ) ) { addError ( "userRegister.error.missingOpenIDOrPassword" ) ; return INPUT ; } else if ( StringUtils . isNotEmpty ( bean . getOpenIdUrl ( ) ) && StringUtils . isNotEmpty ( bean . getPasswordText ( ) ) ) { addError ( "userRegister.error.bothOpenIDAndPassword" ) ; return INPUT ; } } if ( authMethod . equals ( AuthMethod . OPENID ) || ( authMethod . equals ( AuthMethod . DB_OPENID ) && ! StringUtils . isEmpty ( bean . getOpenIdUrl ( ) ) ) ) { String randomString = RandomStringUtils . randomAlphanumeric ( 255 ) ; try { existingUser . resetPassword ( randomString ) ; } catch ( WebloggerException e ) { addMessage ( "yourProfile.passwordResetError" ) ; } } if ( ! StringUtils . isEmpty ( getBean ( ) . getPasswordText ( ) ) && ! StringUtils . isEmpty ( getBean ( ) . getPasswordConfirm ( ) ) ) { try { existingUser . resetPassword ( getBean ( ) . getPasswordText ( ) ) ; } catch ( WebloggerException e ) { addMessage ( "yourProfile.passwordResetError" ) ; } } try { UserManager mgr = WebloggerFactory . getWeblogger ( ) . getUserManager ( ) ; mgr . saveUser ( existingUser ) ; WebloggerFactory . getWeblogger ( ) . flush ( ) ; addMessage ( "generic.changes.saved" ) ; return SUCCESS ; } catch ( WebloggerException ex ) { log . error ( "ERROR in action" , ex ) ; addError ( "Unexpected error doing profile save" ) ; } } return INPUT ; } public void myValidate ( ) { if ( StringUtils . isEmpty ( getBean ( ) . getOpenIdUrl ( ) ) ) { if ( ! StringUtils . equals ( getBean ( ) . getPasswordText ( ) , getBean ( ) . getPasswordConfirm ( ) ) ) { addError ( "userRegister.error.mismatchedPasswords" ) ; } if ( authMethod == AuthMethod . OPENID ) { addError ( "userRegister.error.missingOpenID" ) ; } } else { try { UserManager mgr = WebloggerFactory . getWeblogger ( ) . getUserManager ( ) ; User user = mgr . getUserByOpenIdUrl ( bean . getOpenIdUrl ( ) ) ; if ( user != null && ! ( user . getUserName ( ) . equals ( bean . getUserName ( ) ) ) ) { addError ( "error.add.user.openIdInUse" ) ; } } catch ( WebloggerException ex ) { log . error ( "error checking OpenID URL" , ex ) ; addError ( "generic.error.check.logs" ) ; } } } public String getAuthMethod ( ) { return authMethod . name ( ) ; } public ProfileBean getBean ( ) { return bean ; } public void setBean ( ProfileBean bean ) { this . bean = bean ; } }